def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complex_factor = 1.0
        adaptive_penalty = 0.0
        oscillation = 1.0
        modulation = 1.0
        weighted_sum = 0.0
        exponential_decay = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        for depth in range(1, 10):
            oscillation *= np.cos(ratio * depth)
            modulation *= (1 - 1 / (depth + ratio + 2))
            adaptive_penalty += ((-1) ** depth) * (ratio ** (depth * 1.5)) / (depth ** 2 + 1)
            weighted_sum += (ratio ** depth) / (depth * (depth + 1))
        exponential_decay = np.exp(-ratio / (capacity + 1))
        if ratio > 5:
            penalty = 0.0
            for k in range(1, 8):
                penalty += ((ratio ** (2 * k)) / (k ** 4 + 3)) * np.sin(ratio / (k + 1))
            score = (ratio ** 4) / 5 + penalty
            score *= (exponential_decay + modulation) * oscillation
            if item > capacity * 6:
                score *= 4
            else:
                score *= 2.5
        elif 3 < ratio <= 5:
            temp_score = 0.0
            for x in range(1, 12):
                sign = (-1) ** (x + 1)
                temp_score += sign * (ratio ** (x + 0.5)) / (x ** 2 + 1)
            score = abs(temp_score) * modulation * 10
            if ratio > 4.5:
                for m in range(1, 5):
                    score += (ratio ** m) / (m + 2)
        elif 1.5 < ratio <= 3:
            temp = 0.0
            for p in range(1, 14):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                else:
                    temp -= (ratio ** p) / (p * 6)
            multiplier = 30 if ratio < 2 else 20 if ratio < 2.5 else 12
            score = abs(temp) * multiplier
            extra = 0.0
            for q in range(1, 8):
                extra += ((-1) ** q) * (ratio ** q) / (q + 3)
            score += abs(extra) * 3
            score *= exponential_decay
        elif 0 < ratio <= 1.5:
            temp_score = 0.0
            for y in range(1, 20):
                if y % 5 == 0:
                    temp_score += (ratio ** y) / (y * 4)
                elif y % 2 == 0:
                    temp_score -= (ratio ** y) / (y * 3)
                else:
                    temp_score += (ratio ** y) / (y * 5)
            if ratio < 0.3:
                multiplier = 35
            elif ratio < 0.7:
                multiplier = 20
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier * oscillation
            if ratio > 1.2:
                extra_penalties = 0.0
                for n in range(1, 9):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 1.5
        else:
            if item == 0:
                score = 0
            else:
                score = np.inf
        if score != np.inf:
            complexity_adjustment = 1.0
            for r in range(1, 5):
                complexity_adjustment *= (1 + r / (bins[i] + r + 1))
            priority = score * complexity_adjustment
            if priority < 0:
                priority = np.inf
            priorities[i] = priority
        else:
            priorities[i] = np.inf
    return priorities
